    \mathcal{F}(m, \mathbb{D}) = \frac{1}{|\mathbb{D}|} \sum_{g \in \mathbb{D}} \frac{\text{count}(m, g)}{\sum_{m' \in M} \text{count}(m', g)}
\end{equation}

\paragraph{Weighted Average Depth.} To better capture the hierarchical nature of discourse graphs, we also calculate the average depths of each motif $m$ appearing in a graph $g$. In our graph, the depth is measured by computing the distance from the root node $m_{root}$ to 
\begin{equation}
    \mathcal{D}(m, \mathbb{D}) = \frac{1}{|\mathbb{D}|} \sum_{g \in \mathbb{D}} \frac{\text{count}(m, g)\cdot\text{dist}(m_{root}, m)}{\sum_{m' \in M} \text{count}(m', g)}
\end{equation}



\subsubsection{Motif Frequency-Inverse Document Frequency (MF-IDF)}\label{subsubsec:mfidf}
Inspired by the term frequency–inverse document frequency (TF-IDF) measure from information retrieval domain, we propose ``motif frequency–inverse document frequency'' (MF-IDF), noting that a motif ($m$) can be considered as a vocabulary of documents that are graphs ($g \in \mathbb{G}$) in our case:

\begin{align*}
    \text{MF-IDF}(m, g, \mathbb{G}) = \text{MF}(m, g) \cdot \text{IDF}(g, \mathbb{G})
\end{align*}

where:
\begin{align*}
    \text{MF}(m, g) = \frac{f_{m, g}}{\sum_{m'\in g}f_{m', g}} \\
    \text{IDF}(g, \mathbb{G}) = \log \frac{1 + |\mathbb{G}|}{1 + |g \in \mathbb{G}: m \in g|} \\
    f_{m, g} = \text{occurences of motif $m$ in graph $g$.}
\end{align*}

