\centering
\begin{tabular}{c}
   {\includegraphics[width=0.9\textwidth]{figures/motif_diff_dist-norm_by_edges.pdf}}  \\
     (a) Difference distribution of motifs computed by using their motif frequencies.\\
     \includegraphics[width=0.9\textwidth]{figures/motif_mfidf_scores_difference.pdf}  \\
     (b) Difference distribution of motifs computed by using their MF-IDF scores.
\end{tabular}
\caption{Two ways of computing the difference distributions.}
\label{fig:difference_dists_two_ways}
\end{figure*}


